  border: none;
  border-radius: var(--radius-xs);
  background: transparent;
  padding: 0.3rem 0.4rem;
  font-size: 0.78rem;
  color: var(--card-foreground);
  text-align: left;
  text-decoration: none;
  cursor: pointer;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.sidebar-item:hover {
  background: var(--hover);
}

.sidebar-item--active {
  background: var(--active);
  color: var(--foreground);
  font-weight: 600;
}

.sidebar-project-item {
  font-weight: 600;
}

.sidebar-agent-item {
  color: var(--muted-foreground);
  cursor: default;
}

.sidebar-nav-item {
  margin: 0 0.5rem;
  font-weight: 600;
}

.sidebar-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 0.05rem;
}

.sidebar-branch-list {
  padding-left: 0;
}

.sidebar-conversation-item--branch {
  font-size: 0.72rem;
  color: var(--muted-foreground);
}

.seed-panel {
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  background: var(--card);
  padding: 0.75rem;
}

.seed-panel h3 {
