:root {
  font-family: "Instrument Sans", system-ui, sans-serif;
  -webkit-font-smoothing: antialiased;

  /* Dark mode — default, matching landing page palette */
  --background: #0a0a0c;
  --foreground: #e8e6e3;
  --card: #111114;
  --card-foreground: #e8e6e3;
  --muted: #18181c;
  --muted-foreground: #9a9a9a;
  --border: #1e1e26;
  --input: #1e1e26;
  --ring: #c4f042;
  --destructive: #d66a8a;

  /* Hover/active surface variants */
  --hover: #2a2a32;
  --active: #32323c;

  /* Accent / brand */
  --accent: #c4f042;
  --accent-glow: rgba(196, 240, 66, 0.08);
  --accent-hover: #d4ff52;

  /* Typography */
  --font-mono: "JetBrains Mono", monospace;

  /* Radius */
  --radius: 12px;
  --radius-sm: 8px;
  --radius-xs: 6px;

  /* Entity accent palette — mapped to landing page colors */
  --entity-project: #5b8dee;
  --entity-feature: #6ee7b7;
  --entity-task: #c4f042;
  --entity-decision: #e8944a;
  --entity-question: #a78bfa;
  --entity-person: #d66a8a;

  /* Entity foregrounds — light tints for text on accent backgrounds */
  --entity-project-fg: #c4d8f8;
  --entity-feature-fg: #c4f5e4;
  --entity-task-fg: #e8f8b0;
  --entity-decision-fg: #f5d4a8;
  --entity-question-fg: #d8c8f8;
  --entity-person-fg: #f0c0d0;

  /* Entity muted variants — dark subtle backgrounds */
  --entity-project-muted: #161c2a;
  --entity-feature-muted: #142420;
  --entity-task-muted: #1c2010;
  --entity-decision-muted: #241c12;
  --entity-question-muted: #1c162a;
  --entity-person-muted: #2a1620;

  /* Governance tiers */
  --tier-blocking: #d66a8a;
  --tier-blocking-muted: #2a1a20;
  --tier-review: #e8944a;
  --tier-review-muted: #2a221a;
  --tier-awareness: #6ee7b7;
  --tier-awareness-muted: #1a2a22;
}

.light {
  --background: #fafaf9;
  --foreground: #1a1a1c;
  --card: #ffffff;
  --card-foreground: #1a1a1c;
  --muted: #f0f0ed;
  --muted-foreground: #6a6a6a;
  --border: #e2e2dd;
  --input: #e2e2dd;
  --ring: #a0c830;
  --hover: #eaeae5;
  --active: #e0e0da;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  min-height: 100vh;
  background: var(--background);
  color: var(--foreground);
}

.app-shell {
  display: flex;
  height: 100vh;
  overflow: hidden;
}

.app-main {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-width: 0;
  background: var(--background);
}

.content-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0.55rem 0.85rem;
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
}

.content-header-title {
  font-weight: 700;
  font-size: 0.88rem;
  color: var(--foreground);
}

.onboarding-badge {
  font-size: 0.7rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  padding: 0.2rem 0.5rem;
  border: 1px solid var(--entity-feature);
  color: var(--entity-feature);
  background: var(--entity-feature-muted);
}

.app-content {
  flex: 1;
  overflow-y: auto;
  min-height: 0;
}

.workspace-toolbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 0.6rem;
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  background: var(--muted);
  padding: 0.6rem 0.8rem;
}

.seed-toggle {
  border: 1px solid var(--border);
  border-radius: var(--radius-xs);
  background: var(--card);
  color: var(--foreground);
  padding: 0.42rem 0.7rem;
  font-size: 0.78rem;
  font-weight: 700;
  cursor: pointer;
}

.workspace-state {
  margin-left: 0.6rem;
  font-size: 0.8rem;
  font-weight: 600;
  color: var(--muted-foreground);
}

.pending-file {
  display: inline-flex;
  align-items: center;
  gap: 0.45rem;
  font-size: 0.8rem;
}

.pending-file button {
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  background: var(--card);
  color: var(--foreground);
  cursor: pointer;
  padding: 0.2rem 0.45rem;
}

.onboarding-action-buttons {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
  padding: 0.1rem 0.1rem 0.2rem;
}

.onboarding-action-buttons button {
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  background: var(--card);
  color: var(--foreground);
  padding: 0.42rem 0.7rem;
  font-size: 0.78rem;
  font-weight: 700;
  cursor: pointer;
}

.onboarding-action-buttons button:disabled {
  cursor: not-allowed;
  color: var(--muted-foreground);
  border-color: var(--border);
}

.chat-main {
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  gap: 0.75rem;
  min-height: 0;
}

.chat-main--with-seeds {
  grid-template-columns: minmax(0, 1fr) 280px;
}

/* Workspace sidebar — full-height left panel */
.workspace-sidebar {
  width: 200px;
  flex-shrink: 0;
  border-right: 1px solid var(--border);
  background: var(--card);
  display: flex;
  flex-direction: column;
  padding: 0.5rem 0;
  overflow-y: auto;
}

.sidebar-section {
  display: flex;
  flex-direction: column;
  padding: 0 0.5rem;
}

.sidebar-section--chats {
  flex: 1;
  min-height: 0;
  overflow-y: auto;
}

.sidebar-section-label {
  font-size: 0.68rem;
  font-weight: 700;
  color: var(--muted-foreground);
  text-transform: uppercase;
  letter-spacing: 0.04em;
  padding: 0.45rem 0.35rem 0.2rem;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.sidebar-new-chat-btn {
  border: none;
  background: transparent;
  color: var(--muted-foreground);
  font-size: 1rem;
  font-weight: 700;
  cursor: pointer;
  line-height: 1;
  padding: 0 0.2rem;
  border-radius: var(--radius-sm);
}

.sidebar-new-chat-btn:hover {
  background: var(--hover);
  color: var(--foreground);
}

.sidebar-divider {
  height: 1px;
  background: var(--border);
  margin: 0.35rem 0.5rem;
}

.sidebar-item {
  display: block;
  width: 100%;
  border: none;
  border-radius: var(--radius-xs);
  background: transparent;
  padding: 0.3rem 0.4rem;
  font-size: 0.78rem;
  color: var(--card-foreground);
  text-align: left;
  text-decoration: none;
  cursor: pointer;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.sidebar-item:hover {
  background: var(--hover);
}

.sidebar-item--active {
  background: var(--active);
  color: var(--foreground);
  font-weight: 600;
}

.sidebar-project-item {
  font-weight: 600;
}

.sidebar-agent-item {
  color: var(--muted-foreground);
  cursor: default;
}

.sidebar-nav-item {
  margin: 0 0.5rem;
  font-weight: 600;
}

.sidebar-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 0.05rem;
}

.sidebar-branch-list {
  padding-left: 0;
}

.sidebar-conversation-item--branch {
  font-size: 0.72rem;
  color: var(--muted-foreground);
}

.seed-panel {
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  background: var(--card);
  padding: 0.75rem;
}

.seed-panel h3 {
  margin: 0;
  font-size: 0.92rem;
  color: var(--foreground);
}

.seed-panel p {
  margin: 0.35rem 0 0.7rem;
  font-size: 0.78rem;
  color: var(--muted-foreground);
}

.seed-panel ul {
  list-style: none;
