  gap: 0.75rem;
  min-height: 0;
}

.chat-main--with-seeds {
  grid-template-columns: minmax(0, 1fr) 280px;
}

/* Workspace sidebar — full-height left panel */
.workspace-sidebar {
  width: 200px;
  flex-shrink: 0;
  border-right: 1px solid var(--border);
  background: var(--card);
  display: flex;
  flex-direction: column;
  padding: 0.5rem 0;
  overflow-y: auto;
}

.sidebar-section {
  display: flex;
  flex-direction: column;
  padding: 0 0.5rem;
}

.sidebar-section--chats {
  flex: 1;
  min-height: 0;
  overflow-y: auto;
}

.sidebar-section-label {
  font-size: 0.68rem;
  font-weight: 700;
  color: var(--muted-foreground);
  text-transform: uppercase;
  letter-spacing: 0.04em;
  padding: 0.45rem 0.35rem 0.2rem;
