}

.consent-user {
  margin: 0 0 1.25rem;
  color: var(--muted-foreground);
  font-size: 0.8125rem;
}

.consent-scopes {
  margin-bottom: 1.25rem;
}

.consent-scopes-label {
  margin: 0 0 0.5rem;
  color: var(--muted-foreground);
  font-size: 0.8125rem;
}

.consent-scope-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 0.375rem;
}

.consent-scope-item {
