  background: var(--muted);
  color: var(--muted-foreground);
}

.chat-tool-name {
  font-weight: 600;
}

.chat-tool-status--running {
  color: var(--ring);
}

.suggestion-tool-card {
  border: 1px solid;
  padding: 0.5rem 0.75rem;
  font-size: 0.8rem;
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
}

.suggestion-tool-card-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.suggestion-tool-card-category {
  font-size: 0.7rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.suggestion-tool-card-confidence {
  font-size: 0.7rem;
  color: var(--muted-foreground);
}

.suggestion-tool-card-text {
  font-weight: 500;
}

.suggestion-tool-card-rationale {
  color: var(--muted-foreground);
  font-size: 0.75rem;
}

.suggestion-tool-card-target {
  color: var(--muted-foreground);
  font-size: 0.7rem;
  font-style: italic;
}

.chat-input-container {
  display: flex;
  align-items: flex-end;
  gap: 0.5rem;
  border: 1px solid var(--border);
  background: var(--card);
  padding: 0.5rem;
}

.chat-input {
  flex: 1;
  resize: none;
  border: none;
  background: transparent;
  color: var(--foreground);
  font-family: inherit;
  font-size: 0.88rem;
  line-height: 1.45;
  padding: 0.3rem 0.4rem;
  outline: none;
}

.chat-input::placeholder {
  color: var(--muted-foreground);
}

.chat-input-btn {
  border: 1px solid var(--border);
  background: var(--muted);
  color: var(--foreground);
  padding: 0.35rem 0.75rem;
  font-size: 0.78rem;
  font-weight: 700;
  cursor: pointer;
  white-space: nowrap;
}

.chat-input-btn:hover:not(:disabled) {
  background: var(--hover);
}

.chat-input-btn:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

.chat-input-btn--stop {
  border-color: var(--destructive);
  color: var(--destructive);
}

/* ── Sign-In Page ── */

.sign-in-page {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  background: var(--background);
  padding: 1rem;
}

.sign-in-card {
  width: 100%;
  max-width: 380px;
  background: var(--card);
  border: 1px solid var(--border);
  padding: 2rem;
}

.sign-in-title {
  margin: 0 0 0.25rem;
  font-size: 1.5rem;
  font-weight: 600;
  color: var(--card-foreground);
}

.sign-in-subtitle {
  margin: 0 0 1.5rem;
  color: var(--muted-foreground);
  font-size: 0.875rem;
}

.sign-in-loading {
  color: var(--muted-foreground);
  text-align: center;
}

.sign-in-form {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.sign-in-input {
  width: 100%;
  padding: 0.5rem 0.75rem;
  background: var(--background);
  border: 1px solid var(--input);
  color: var(--foreground);
  font-family: inherit;
  font-size: 0.875rem;
}

.sign-in-input:focus {
  outline: none;
  border-color: var(--ring);
}

.sign-in-error {
  margin: 0;
  color: var(--destructive);
  font-size: 0.8125rem;
}

.sign-in-button {
  width: 100%;
  padding: 0.5rem;
  background: var(--ring);
  border: 1px solid transparent;
  color: var(--foreground);
  font-family: inherit;
  font-size: 0.875rem;
  font-weight: 500;
  cursor: pointer;
}

.sign-in-button:hover {
  opacity: 0.9;
}

.sign-in-button:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.sign-in-github {
  background: var(--muted);
}

.sign-in-divider {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  margin: 1rem 0;
  color: var(--muted-foreground);
  font-size: 0.8125rem;
}

.sign-in-divider::before,
.sign-in-divider::after {
  content: "";
