  border-top: 1px solid var(--border);
}

.sign-in-switch {
  margin: 1rem 0 0;
  text-align: center;
  color: var(--muted-foreground);
  font-size: 0.8125rem;
}

.sign-in-switch button {
  background: none;
  border: none;
  color: var(--ring);
  cursor: pointer;
  font-family: inherit;
  font-size: inherit;
  padding: 0;
  text-decoration: underline;
}

