}

.consent-scope-desc {
  color: var(--card-foreground);
}

.consent-scope-name {
  color: var(--muted-foreground);
  font-size: 0.75rem;
  font-family: var(--font-mono);
}

.consent-error {
  margin: 0 0 1rem;
  color: var(--destructive);
  font-size: 0.8125rem;
}

.consent-actions {
  display: flex;
  gap: 0.75rem;
}

.consent-button {
  flex: 1;
  padding: 0.5rem;
  border: 1px solid transparent;
  font-family: inherit;
  font-size: 0.875rem;
  font-weight: 500;
  cursor: pointer;
  color: var(--foreground);
}

.consent-button:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.consent-allow {
  background: var(--ring);
}

.consent-allow:hover {
  opacity: 0.9;
}

.consent-deny {
  background: var(--muted);
}

.consent-deny:hover {
  background: var(--hover);
}

