653→(function() {
654→  function initHeroGraph() {
655→    var reduceMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
656→    var mobile = window.matchMedia('(max-width: 768px)').matches;
657→    if (reduceMotion || mobile) return;
658→
659→    var canvas = document.querySelector('.hero-graph');
660→    if (!canvas) return;
661→    var ctx = canvas.getContext('2d');
662→    if (!ctx) return;
663→
664→    var width = 0;
665→    var height = 0;
666→    var dpr = 1;
667→    var nodes = [];
668→    var raf = 0;
669→    var maxDist = 96;
670→    var t = 0;
671→
672→    function sampleLobe(cx, cy, rx, ry) {
673→      var x = cx;
674→      var y = cy;
675→      for (var i = 0; i < 32; i++) {
676→        x = cx + (Math.random() * 2 - 1) * rx;
677→        y = cy + (Math.random() * 2 - 1) * ry;
678→        var nx = (x - cx) / rx;
679→        var ny = (y - cy) / ry;
680→        // Soft superellipse for a brain-like lobe silhouette.
681→        if (Math.pow(Math.abs(nx), 2.35) + Math.pow(Math.abs(ny), 2.05) <= 1) break;
682→      }
683→      return { x: x, y: y };
684→    }
685→
686→    function pushNode(x, y, zone) {
687→      nodes.push({
688→        ax: x,
689→        ay: y,
690→        x: x,
691→        y: y,
692→        phaseX: Math.random() * Math.PI * 2,
693→        phaseY: Math.random() * Math.PI * 2,
694→        speedX: 1 + Math.random() * 0.9,
695→        speedY: 1 + Math.random() * 0.9,
696→        ampX: 2.6 + Math.random() * 4.2,
697→        ampY: 2.2 + Math.random() * 3.8,
698→        zone: zone,
699→        hue: Math.random() < 0.2 ? 'blue' : 'accent'
700→      });
701→    }
702→
703→    function sampleField() {
704→      return {
705→        x: Math.random() * width,
706→        y: Math.random() * height
707→      };
708→    }
709→
710→    function makeNodes() {
711→      nodes = [];
712→      var cx = width * 0.5;
713→      var cy = height * 0.52;
714→      var lx = width * 0.3;
715→      var rx = width * 0.7;
716→      var lobeRx = width * 0.24;
717→      var lobeRy = height * 0.4;
718→      var perLobe = Math.max(38, Math.min(62, Math.floor((width * height) / 12500)));
719→      var bridgeCount = Math.max(8, Math.min(14, Math.floor(perLobe * 0.16)));
720→      var fieldCount = Math.max(30, Math.min(60, Math.floor((width * height) / 17000)));
721→
722→      for (var i = 0; i < perLobe; i++) {
723→        var left = sampleLobe(lx, cy, lobeRx, lobeRy);
724→        var right = sampleLobe(rx, cy, lobeRx, lobeRy);
725→        pushNode(left.x, left.y, 'left');
726→        pushNode(right.x, right.y, 'right');
727→      }
728→
729→      for (var i = 0; i < bridgeCount; i++) {
730→        var p = i / Math.max(1, bridgeCount - 1);
731→        var bx = cx + (Math.random() - 0.5) * width * 0.28;
732→        var by = cy - height * 0.14 + p * height * 0.28 + (Math.random() - 0.5) * height * 0.05;
733→        pushNode(bx, by, 'bridge');
734→      }
735→
736→      for (var i = 0; i < fieldCount; i++) {
737→        var outer = sampleField();
738→        pushNode(outer.x, outer.y, 'field');
739→      }
740→    }
741→
742→    function resize() {
743→      var rect = canvas.getBoundingClientRect();
744→      width = Math.max(1, rect.width);
745→      height = Math.max(1, rect.height);
746→      dpr = Math.min(window.devicePixelRatio || 1, 2);
