748→      canvas.height = Math.floor(height * dpr);
749→      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
750→      maxDist = Math.max(70, Math.min(112, width * 0.1));
751→      makeNodes();
752→    }
753→
754→    function edgeFactor(a, b) {
755→      if (a.zone === 'field' || b.zone === 'field') return 0.88;
756→      if (a.zone === 'bridge' || b.zone === 'bridge') return 1.16;
757→      if ((a.zone === 'left' && b.zone === 'right') || (a.zone === 'right' && b.zone === 'left')) return 0.72;
758→      return 1;
759→    }
760→
761→    function draw() {
762→      if (document.hidden) {
763→        raf = requestAnimationFrame(draw);
764→        return;
765→      }
766→
767→      t += 0.024;
768→      ctx.clearRect(0, 0, width, height);
769→
770→      var swayX = Math.sin(t * 0.21) * 7.5;
771→      var swayY = Math.cos(t * 0.18) * 4.2;
772→
773→      for (var i = 0; i < nodes.length; i++) {
774→        var n = nodes[i];
775→        var zoneShiftX = n.zone === 'left' ? -swayX : n.zone === 'right' ? swayX : n.zone === 'field' ? swayX * 0.2 : 0;
776→        var zoneShiftY = n.zone === 'bridge' ? swayY * 0.45 : n.zone === 'field' ? swayY * 0.2 : swayY;
777→        n.x = n.ax + Math.sin(t * n.speedX + n.phaseX) * n.ampX + zoneShiftX;
778→        n.y = n.ay + Math.cos(t * n.speedY + n.phaseY) * n.ampY + zoneShiftY;
779→      }
780→
781→      for (var i = 0; i < nodes.length; i++) {
782→        var a = nodes[i];
783→        for (var j = i + 1; j < nodes.length; j++) {
784→          var b = nodes[j];
785→          var dx = a.x - b.x;
786→          var dy = a.y - b.y;
787→          var dist = Math.sqrt(dx * dx + dy * dy);
788→          var threshold = maxDist * edgeFactor(a, b);
789→          if (dist > threshold) continue;
790→          var strength = 1 - dist / threshold;
791→          var alpha = strength * strength * 0.33;
792→          var stroke = a.hue === 'blue' || b.hue === 'blue'
793→            ? 'rgba(91,141,238,' + (alpha * 0.68) + ')'
794→            : 'rgba(196,240,66,' + alpha + ')';
795→          ctx.strokeStyle = stroke;
796→          ctx.lineWidth = 1;
797→          ctx.beginPath();
798→          ctx.moveTo(a.x, a.y);
799→          ctx.lineTo(b.x, b.y);
800→          ctx.stroke();
801→        }
802→      }
803→
804→      for (var i = 0; i < nodes.length; i++) {
805→        var node = nodes[i];
806→        ctx.beginPath();
807→        var radius = node.zone === 'bridge' ? 2 : node.zone === 'field' ? 1.45 : 1.7;
808→        ctx.arc(node.x, node.y, radius, 0, Math.PI * 2);
809→        ctx.fillStyle = node.hue === 'blue'
810→          ? 'rgba(91,141,238,0.58)'
811→          : 'rgba(196,240,66,0.64)';
812→        ctx.fill();
813→      }
814→
815→      raf = requestAnimationFrame(draw);
816→    }
817→
818→    resize();
819→    window.addEventListener('resize', resize);
820→    raf = requestAnimationFrame(draw);
821→  }
