823→  var els = document.querySelectorAll('.reveal');
824→  
825→  function revealCheck() {
826→    var wh = window.innerHeight || document.documentElement.clientHeight;
827→    for (var i = 0; i < els.length; i++) {
828→      var rect = els[i].getBoundingClientRect();
