const lines = FILE_CONTENT.split('\n');

// Find all major CSS selectors and their line ranges
const selectors = [];
let braceDepth = 0;
let currentSelector = null;

for (let i = 0; i < lines.length; i++) {
  const line = lines[i];
  const trimmed = line.trim();

  if (braceDepth === 0 && trimmed.includes('{') && !trimmed.startsWith('/*')) {
    currentSelector = { name: trimmed.replace('{', '').trim(), startLine: i + 1 };
  }

  for (const ch of line) {
    if (ch === '{') braceDepth++;
    if (ch === '}') braceDepth--;
  }

  if (braceDepth === 0 && currentSelector) {
    currentSelector.endLine = i + 1;
    selectors.push(currentSelector);
    currentSelector = null;
  }
}

// Group by categories
const categories = {
  'Layout/App Shell': [],
  'Sidebar': [],
  'Chat': [],
  'Entity': [],
  'Graph': [],
  'Cards/Surfaces': [],
  'Buttons/Inputs': [],
  'Typography/Text': [],
  'Animations': [],
  'Other': [],
};

for (const sel of selectors) {
  const n = sel.name.toLowerCase();
  if (n.includes('sidebar') || n.includes('.nav')) categories['Sidebar'].push(sel);
  else if (n.includes('app-shell') || n.includes('app-content') || n.includes('content-header') || n.includes('.layout')) categories['Layout/App Shell'].push(sel);
  else if (n.includes('chat') || n.includes('message') || n.includes('.msg')) categories['Chat'].push(sel);
  else if (n.includes('entity') || n.includes('work-item') || n.includes('suggestion')) categories['Entity'].push(sel);
  else if (n.includes('graph') || n.includes('node') || n.includes('edge')) categories['Graph'].push(sel);
  else if (n.includes('card') || n.includes('surface') || n.includes('panel') || n.includes('modal') || n.includes('dialog')) categories['Cards/Surfaces'].push(sel);
  else if (n.includes('btn') || n.includes('button') || n.includes('input') || n.includes('textarea') || n.includes('select') || n.includes('form')) categories['Buttons/Inputs'].push(sel);
  else if (n.includes('heading') || n.includes('title') || n.includes('label') || n.includes('text') || n.includes('code') || n.includes('mono')) categories['Typography/Text'].push(sel);
  else if (n.includes('@keyframe') || n.includes('animation') || n.includes('transition')) categories['Animations'].push(sel);
  else categories['Other'].push(sel);
}

for (const [cat, sels] of Object.entries(categories)) {
  if (sels.length === 0) continue;
  console.log(`\n=== ${cat} (${sels.length} rules) ===`);
  for (const s of sels.slice(0, 20)) {
    console.log(`  L${s.startLine}-${s.endLine}: ${s.name}`);
  }
  if (sels.length > 20) console.log(`  ... and ${sels.length - 20} more`);
}

// Also find border-radius usage
const radiusLines = lines.filter((l, i) => l.includes('border-radius'));
console.log(`\n=== Border-radius occurrences: ${radiusLines.length} ===`);
radiusLines.forEach(l => console.log('  ' + l.trim()));

// Find font-family usage
const fontLines = lines.filter(l => l.includes('font-family'));
console.log(`\n=== Font-family occurrences ===`);
fontLines.forEach(l => console.log('  ' + l.trim()));

// Find box-shadow usage
const shadowLines = lines.filter(l => l.includes('box-shadow'));
console.log(`\n=== Box-shadow occurrences: ${shadowLines.length} ===`);
shadowLines.forEach(l => console.log('  ' + l.trim()));

// Find transition usage
const transLines = lines.filter(l => l.includes('transition:'));
console.log(`\n=== Transition occurrences: ${transLines.length} ===`);
transLines.slice(0, 10).forEach(l => console.log('  ' + l.trim()));
if (transLines.length > 10) console.log(`  ... and ${transLines.length - 10} more`);

