const lines = FILE_CONTENT.split('\n');

// Extract key sections we haven't fully read yet
const sections = [
  { name: 'Chat page/messages/input', start: 1854, end: 2050 },
  { name: 'Entity detail panel', start: 810, end: 1050 },
  { name: 'Feed/governance', start: 1220, end: 1600 },
  { name: 'Search overlay', start: 1600, end: 1810 },
  { name: 'Graph toolbar/canvas', start: 730, end: 815 },
  { name: 'Auth pages (sign-in/consent)', start: 2100, end: 2371 },
];

for (const sec of sections) {
  console.log(`\n=== ${sec.name} (L${sec.start}-${sec.end}) ===`);
  for (let i = sec.start - 1; i < Math.min(sec.end, lines.length); i++) {
    const line = lines[i];
    const trimmed = line.trim();
    // Only print selectors and key properties
    if (trimmed === '' || trimmed === '}' || trimmed.startsWith('/*')) continue;
    if (!trimmed.startsWith('.') && !trimmed.startsWith('#') && !trimmed.startsWith('@') && 
        !trimmed.includes('{') && !trimmed.includes('border-radius') && 
        !trimmed.includes('background') && !trimmed.includes('border:') &&
        !trimmed.includes('box-shadow') && !trimmed.includes('color:') &&
        !trimmed.includes('font') && !trimmed.includes('transition') &&
        !trimmed.includes('backdrop') && !trimmed.includes('border-color')) continue;
    console.log(`  L${i+1}: ${trimmed}`);
  }
}

