 10→import { useViewState } from "../../stores/view-state";
 11→import { acceptSuggestion, confirmDecision, convertSuggestion, deferSuggestion, dismissSuggestion, markTaskComplete, overrideDecision, setEntityPriority } from "../../graph/actions";
 12→
 13→const CONFIRMABLE_STATUSES = new Set(["extracted", "proposed", "provisional", "inferred"]);
 14→
 15→const CATEGORY_TO_ENTITY_TYPE: Record<string, "task" | "feature" | "decision" | "project"> = {
 16→  optimization: "task",
 17→  risk: "decision",
 18→  opportunity: "feature",
 19→  conflict: "decision",
 20→  missing: "task",
 21→  pivot: "project",
 22→};
 23→
 24→export function EntityDetailPanel({
 25→  entityId,
 26→  workspaceId,
 27→  onClose,
 28→  onEntityClick,
 29→}: {
 30→  entityId: string;
 31→  workspaceId: string;
 32→  onClose: () => void;
 33→  onEntityClick: (entityId: string) => void;
 34→}) {
 35→  const [detail, setDetail] = useState<EntityDetailResponse | undefined>();
 36→  const [loading, setLoading] = useState(true);
 37→  const [error, setError] = useState<string | undefined>();
 38→  const [actionPending, setActionPending] = useState(false);
 39→  const [showConvertForm, setShowConvertForm] = useState(false);
 40→  const [convertKind, setConvertKind] = useState<"task" | "feature" | "decision" | "project">("task");
 41→  const [convertTitle, setConvertTitle] = useState("");
 42→  const navigateToDiscussEntity = useViewState((s) => s.navigateToDiscussEntity);
 43→  const navigate = useNavigate();
 44→
 45→  useEffect(() => {
 46→    setLoading(true);
 47→    setError(undefined);
 48→
 49→    fetch(`/api/entities/${encodeURIComponent(entityId)}?workspaceId=${encodeURIComponent(workspaceId)}`)
 50→      .then(async (response) => {
 51→        if (!response.ok) {
 52→          const body = await response.text();
 53→          throw new Error(body);
 54→        }
 55→        return response.json() as Promise<EntityDetailResponse>;
 56→      })
 57→      .then((data) => {
 58→        setDetail(data);
 59→        setLoading(false);
 60→      })
 61→      .catch((err) => {
 62→        setError(err instanceof Error ? err.message : "Failed to load entity");
 63→        setLoading(false);
 64→      });
 65→  }, [entityId, workspaceId]);
 66→
 67→  function handleJumpToMessage(messageId: string, conversationId?: string) {
 68→    if (conversationId) {
 69→      void navigate({ to: "/chat/$conversationId", params: { conversationId }, search: { message: messageId } });
 70→    } else {
 71→      void navigate({ to: "/chat", search: { message: messageId } });
 72→    }
 73→  }
 74→
 75→  async function handleConfirm() {
 76→    if (!detail || actionPending) return;
 77→    setActionPending(true);
 78→    try {
 79→      await confirmDecision(workspaceId, entityId);
 80→      setDetail((prev) =>
 81→        prev
 82→          ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, status: "confirmed" } } }
 83→          : prev,
 84→      );
 85→    } finally {
 86→      setActionPending(false);
 87→    }
 88→  }
 89→
 90→  async function handleOverride() {
 91→    if (!detail || actionPending) return;
 92→    const newSummary = window.prompt("New decision summary:");
 93→    if (!newSummary) return;
 94→    setActionPending(true);
 95→    try {
 96→      await overrideDecision(workspaceId, entityId, newSummary);
 97→      setDetail((prev) =>
 98→        prev
 99→          ? {
100→              ...prev,
101→              entity: {
102→                ...prev.entity,
103→                name: newSummary,
104→                data: { ...prev.entity.data, status: "overridden", summary: newSummary },
105→              },
106→            }
107→          : prev,
108→      );
109→    } finally {
110→      setActionPending(false);
111→    }
112→  }
113→
114→  async function handleComplete() {
115→    if (!detail || actionPending) return;
116→    setActionPending(true);
117→    try {
118→      await markTaskComplete(workspaceId, entityId);
119→      setDetail((prev) =>
120→        prev
121→          ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, status: "done" } } }
122→          : prev,
123→      );
124→    } finally {
125→      setActionPending(false);
126→    }
127→  }
128→
129→  if (loading) {
130→    return (
131→      <aside className="entity-detail-panel">
132→        <p className="entity-detail-meta">Loading...</p>
133→      </aside>
134→    );
135→  }
136→
137→  if (error || !detail) {
138→    return (
139→      <aside className="entity-detail-panel">
140→        <div className="entity-detail-header">
141→          <p className="entity-detail-meta">{error ?? "Entity not found"}</p>
142→          <button type="button" className="entity-detail-close" onClick={onClose}>&times;</button>
143→        </div>
144→      </aside>
145→    );
146→  }
147→
148→  const kind = detail.entity.kind as EntityKind;
149→  const status = (detail.entity.data.status as string | undefined) ?? "";
150→  const rationale = detail.entity.data.rationale as string | undefined;
151→
152→  const showConfirm = kind === "decision" && CONFIRMABLE_STATUSES.has(status);
153→  const showOverride = kind === "decision" && CONFIRMABLE_STATUSES.has(status);
154→  const showComplete = kind === "task" && status !== "done";
155→  const showSuggestionActions = kind === "suggestion" && (status === "pending" || status === "deferred");
156→
157→  return (
158→    <aside className="entity-detail-panel">
159→      <div className="entity-detail-header">
160→        <div>
161→          <EntityBadge kind={kind} />
162→          <h3>{detail.entity.name}</h3>
163→        </div>
164→        <button type="button" className="entity-detail-close" onClick={onClose}>&times;</button>
165→      </div>
166→
167→      <div className="entity-detail-section">
168→        <h4>Metadata</h4>
169→        <dl className="entity-detail-meta">
170→          {status ? (
171→            <>
172→              <dt>Status</dt>
173→              <dd>{status}</dd>
174→            </>
175→          ) : undefined}
176→          {typeof detail.entity.data.category === "string" && (ENTITY_CATEGORIES as readonly string[]).includes(detail.entity.data.category) ? (
177→            <>
178→              <dt>Category</dt>
179→              <dd><CategoryBadge category={detail.entity.data.category as EntityCategory} /></dd>
180→            </>
181→          ) : undefined}
182→          {detail.entity.data.confidence !== undefined ? (
183→            <>
184→              <dt>Confidence</dt>
185→              <dd>{(detail.entity.data.confidence as number).toFixed(2)}</dd>
186→            </>
187→          ) : undefined}
188→          {detail.entity.data.created_at ? (
189→            <>
190→              <dt>Created</dt>
191→              <dd>{new Date(detail.entity.data.created_at as string).toLocaleDateString()}</dd>
192→            </>
193→          ) : undefined}
194→          {detail.entity.data.owner_name ? (
195→            <>
196→              <dt>Owner</dt>
197→              <dd>{detail.entity.data.owner_name as string}</dd>
198→            </>
199→          ) : undefined}
200→          {(kind === "task" || kind === "decision" || kind === "question") ? (
201→            <>
202→              <dt>Priority</dt>
203→              <dd>
204→                <select
205→                  value={(detail.entity.data.priority as string | undefined) ?? ""}
206→                  disabled={actionPending}
207→                  onChange={async (e) => {
208→                    const value = e.target.value as EntityPriority;
209→                    if (!value) return;
210→                    setActionPending(true);
211→                    try {
212→                      await setEntityPriority(workspaceId, entityId, value);
213→                      setDetail((prev) =>
214→                        prev
215→                          ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, priority: value } } }
216→                          : prev,
217→                      );
218→                    } finally {
219→                      setActionPending(false);
220→                    }
221→                  }}
222→                >
223→                  <option value="" disabled>—</option>
224→                  {ENTITY_PRIORITIES.map((p) => (
225→                    <option key={p} value={p}>{p}</option>
226→                  ))}
227→                </select>
228→              </dd>
229→            </>
230→          ) : undefined}
231→        </dl>
232→      </div>
233→
234→      <DescriptionSection data={detail.entity.data} kind={kind} onEntityClick={onEntityClick} />
235→
236→      {rationale ? (
237→        <div className="entity-detail-section">
238→          <h4>Rationale</h4>
239→          <p className="entity-detail-meta">{rationale}</p>
240→        </div>
241→      ) : undefined}
242→
243→      <RelationshipList relationships={detail.relationships} onEntityClick={onEntityClick} />
244→
245→      <ProvenanceSection provenance={detail.provenance} onJumpToMessage={handleJumpToMessage} />
246→
247→      <div className="entity-detail-actions">
248→        <button
249→          type="button"
250→          onClick={() => {
251→            navigateToDiscussEntity({
252→              id: entityId,
253→              kind,
254→              name: detail.entity.name,
255→              ...(status ? { status } : {}),
256→            });
257→            void navigate({ to: "/chat" });
258→          }}
259→        >
260→          Discuss
261→        </button>
262→        {showConfirm ? (
263→          <button type="button" disabled={actionPending} onClick={handleConfirm}>
264→            Confirm
265→          </button>
266→        ) : undefined}
267→        {showOverride ? (
268→          <button type="button" disabled={actionPending} onClick={handleOverride}>
269→            Override
270→          </button>
271→        ) : undefined}
272→        {showComplete ? (
273→          <button type="button" disabled={actionPending} onClick={handleComplete}>
274→            Mark Complete
275→          </button>
276→        ) : undefined}
277→        {showSuggestionActions ? (
278→          <>
279→            <button type="button" disabled={actionPending} onClick={async () => {
280→              setActionPending(true);
281→              try {
282→                await acceptSuggestion(workspaceId, entityId);
283→                setDetail((prev) => prev ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, status: "accepted" } } } : prev);
284→              } finally { setActionPending(false); }
285→            }}>Accept</button>
286→            <button type="button" disabled={actionPending} onClick={() => {
287→              const category = (detail.entity.data.category as string) ?? "";
288→              setConvertKind(CATEGORY_TO_ENTITY_TYPE[category] ?? "task");
289→              setConvertTitle(detail.entity.name);
290→              setShowConvertForm(true);
291→            }}>Convert</button>
292→            <button type="button" disabled={actionPending} onClick={async () => {
293→              setActionPending(true);
294→              try {
295→                await deferSuggestion(workspaceId, entityId);
296→                setDetail((prev) => prev ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, status: "deferred" } } } : prev);
297→              } finally { setActionPending(false); }
298→            }}>Defer</button>
299→            <button type="button" disabled={actionPending} onClick={async () => {
300→              setActionPending(true);
301→              try {
302→                await dismissSuggestion(workspaceId, entityId);
303→                setDetail((prev) => prev ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, status: "dismissed" } } } : prev);
304→              } finally { setActionPending(false); }
305→            }}>Dismiss</button>
306→          </>
307→        ) : undefined}
308→        {showConvertForm ? (
309→          <div className="entity-convert-form">
310→            <label>
311→              Convert to:
312→              <select value={convertKind} onChange={(e) => setConvertKind(e.target.value as typeof convertKind)}>
313→                <option value="task">Task</option>
314→                <option value="feature">Feature</option>
315→                <option value="decision">Decision</option>
316→                <option value="project">Project</option>
317→              </select>
318→            </label>
319→            <label>
320→              Title:
321→              <input type="text" value={convertTitle} onChange={(e) => setConvertTitle(e.target.value)} />
322→            </label>
323→            <div className="entity-convert-form-actions">
324→              <button type="button" disabled={actionPending || !convertTitle.trim()} onClick={async () => {
325→                setActionPending(true);
326→                try {
327→                  await convertSuggestion(workspaceId, entityId, convertKind, convertTitle.trim() || undefined);
328→                  setDetail((prev) => prev ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, status: "converted" } } } : prev);
329→                  setShowConvertForm(false);
330→                } finally { setActionPending(false); }
331→              }}>Confirm</button>
332→              <button type="button" onClick={() => setShowConvertForm(false)}>Cancel</button>
333→            </div>
334→          </div>
335→        ) : undefined}
336→      </div>
337→    </aside>
338→  );
339→}
