  6→export function KnowledgeGraph({
  7→  workspaceId,
  8→  projectId,
  9→  centerId,
 10→  depth,
 11→  selectedId,
 12→  onNodeClick,
 13→}: {
 14→  workspaceId: string;
 15→  projectId?: string;
 16→  centerId?: string;
 17→  depth: number;
 18→  selectedId?: string;
 19→  onNodeClick: (nodeId: string) => void;
 20→}) {
 21→  const [data, setData] = useState<GraphResponse | undefined>();
 22→  const [loading, setLoading] = useState(true);
 23→  const [error, setError] = useState<string | undefined>();
 24→  const graphRef = useRef<GraphCanvasRef>(null);
 25→
 26→  useEffect(() => {
 27→    setLoading(true);
 28→    setError(undefined);
 29→
 30→    const params = new URLSearchParams();
 31→    if (centerId) {
 32→      params.set("center", centerId);
 33→      params.set("depth", String(depth));
 34→    } else if (projectId) {
 35→      params.set("project", projectId);
 36→    }
 37→
 38→    const url = `/api/graph/${encodeURIComponent(workspaceId)}${params.toString() ? `?${params}` : ""}`;
 39→
 40→    fetch(url)
 41→      .then(async (response) => {
 42→        if (!response.ok) {
 43→          throw new Error(await response.text());
 44→        }
 45→        return response.json() as Promise<GraphResponse>;
 46→      })
 47→      .then((result) => {
 48→        setData(result);
 49→        setLoading(false);
 50→      })
 51→      .catch((err) => {
 52→        setError(err instanceof Error ? err.message : "Failed to load graph");
 53→        setLoading(false);
